-- Corrosive Armor Tracker - Settings and Configuration\n-- Provides slash commands and settings management\n\nCorrosiveArmorTracker.Settings = {}\n\n-- Initialize settings and register slash commands\nfunction CorrosiveArmorTracker.Settings.InitializeSettings()\n    -- Register slash commands\n    SLASH_COMMANDS[\"/cat\"] = CorrosiveArmorTracker.Settings.OnSlashCommand\n    \n    d(\"Corrosive Armor Tracker settings available:\")\n    d(\"|cffff00/cat|r - Show current settings\")\n    d(\"|cffff00/cat sound|r - Toggle sound alerts\")\n    d(\"|cffff00/cat visual|r - Toggle visual alerts\")\nend\n\n-- Handle slash command input\nfunction CorrosiveArmorTracker.Settings.OnSlashCommand(command)\n    local args = command:lower()\n    \n    if args == \"\" or args == \"status\" then\n        CorrosiveArmorTracker.Settings.ShowStatus()\n    elseif args == \"sound\" then\n        CorrosiveArmorTracker.Settings.ToggleSound()\n    elseif args == \"visual\" then\n        CorrosiveArmorTracker.Settings.ToggleVisual()\n    else\n        d(\"Unknown command: /cat \" .. args)\n        d(\"Use: /cat, /cat sound, /cat visual\")\n    end\nend\n\n-- Show current settings status\nfunction CorrosiveArmorTracker.Settings.ShowStatus()\n    if not CorrosiveArmorTrackerSavedVars then return end\n    \n    local soundStatus = CorrosiveArmorTrackerSavedVars.enabledSound and \"|c00ff00ON|r\" or \"|cff0000OFF|r\"\n    local visualStatus = CorrosiveArmorTrackerSavedVars.enabledVisual and \"|c00ff00ON|r\" or \"|cff0000OFF|r\"\n    \n    d(\"=== Corrosive Armor Tracker Settings ===\")\n    d(\"Sound Alerts: \" .. soundStatus)\n    d(\"Visual Alerts: \" .. visualStatus)\nend\n\n-- Toggle sound alerts\nfunction CorrosiveArmorTracker.Settings.ToggleSound()\n    if not CorrosiveArmorTrackerSavedVars then return end\n    \n    CorrosiveArmorTrackerSavedVars.enabledSound = not CorrosiveArmorTrackerSavedVars.enabledSound\n    local status = CorrosiveArmorTrackerSavedVars.enabledSound and \"enabled\" or \"disabled\"\n    d(\"Sound alerts \" .. status .. \".\")\nend\n\n-- Toggle visual alerts\nfunction CorrosiveArmorTracker.Settings.ToggleVisual()\n    if not CorrosiveArmorTrackerSavedVars then return end\n    \n    CorrosiveArmorTrackerSavedVars.enabledVisual = not CorrosiveArmorTrackerSavedVars.enabledVisual\n    local status = CorrosiveArmorTrackerSavedVars.enabledVisual and \"enabled\" or \"disabled\"\n    d(\"Visual alerts \" .. status .. \".\")\nend